{
  "primary": null,
  "servers": [
    {
      "name": "localmcp",
      "running": true,
      "error": null,
      "primary": false,
      "builtin": true,
      "transport": "builtin",
      "spec": {
        "transport": "builtin"
      }
    },
    {
      "name": "kubernetes",
      "running": true,
      "error": null,
      "primary": false,
      "builtin": false,
      "transport": "stdio",
      "spec": {
        "name": "kubernetes",
        "transport": "stdio",
        "command": "npx",
        "args": [
          "-y",
          "kubernetes-mcp-server@latest"
        ],
        "compress": {
          "level": "medium",
          "scope": "aggregator"
        }
      }
    },
    {
      "name": "docker",
      "running": true,
      "error": null,
      "primary": false,
      "builtin": false,
      "transport": "stdio",
      "spec": {
        "name": "docker",
        "transport": "stdio",
        "command": "uvx",
        "args": [
          "mcp-server-docker"
        ],
        "env": {
          "DOCKER_HOST": "unix:///var/run/docker.sock"
        }
      }
    },
    {
      "name": "pincher",
      "running": true,
      "error": null,
      "primary": false,
      "builtin": false,
      "transport": "stdio",
      "spec": {
        "name": "pincher",
        "transport": "stdio",
        "command": "pincher",
        "args": [
          "--data-dir",
          "/tmp/pincher",
          "--http",
          "127.0.0.1:8080",
          "--trust-proxy"
        ],
        "reverseProxy": {
          "mount": "/pincher",
          "upstream": "http://127.0.0.1:8080"
        },
        "compress": {
          "level": "medium",
          "scope": "aggregator"
        }
      }
    },
    {
      "name": "filesystem",
      "running": true,
      "error": null,
      "primary": false,
      "builtin": false,
      "transport": "stdio",
      "spec": {
        "name": "filesystem",
        "transport": "stdio",
        "command": "npx",
        "args": [
          "-y",
          "@modelcontextprotocol/server-filesystem",
          "/user_data_rw"
        ]
      }
    }
  ],
  "running": true
}
